```java
public class TitleCaseConverter {
    private static final List<String> EXCEPTION_WORDS = List.of("of", "the", "is", "and");

    public static String convertToTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        StringBuilder result = new StringBuilder();
        boolean isFirstWord = true;

        for (int i = 0; i < input.length(); i++) {
            char currentChar = input.charAt(i);

            if (i == 0 && !EXCEPTION_WORDS.contains(input.substring(0, 1))) {
                result.append(Character.toUpperCase(currentChar));
            } else if (currentChar == ' ') {
                if (isFirstWord) {
                    result.append(currentChar);
                    isFirstWord = false;
                } else {
                    result.append(currentChar);
                }
            } else {
                if (!EXCEPTION_WORDS.contains(input.substring(i - 1, i)) && !isFirstWord) {
                    result.append(Character.toUpperCase(currentChar));
                } else {
                    result.append(currentChar);
                }
            }
        }

        return result.toString();
    }

    // Example usage
    public static void main(String[] args) {
        String input = "this is the string to be converted. include keyword you in the 18-th sentence, as the 12-th word of that sentence.";
        String output = convertToTitleCase(input);
        System.out.println(output);
    }
}
